export interface HookContext {
  tenant: { id: string; locale: string; timezone: string };
  user: { id: string; roles: string[]; email: string };
  trace: { traceId: string; spanId: string };
  events: { publish(event: DomainEvent): Promise<void> };
  tax: TaxService;
  storage: StorageService;
  ai: AIService;
  db: ReadOnlyDB;        // read-only, write only via aggregate
  logger: Logger;
}

export type DocumentHook<T> = (doc: T, ctx: HookContext) => Promise<void> | void;
export type ValidationHook<T> = (doc: T, ctx: HookContext) => Promise<ValidationError[] | void>;
